concept.syntax:
// Return type signals fallibility
fn parse(s: &str) -> Result<i32, ParseIntError> {
    let n = s.trim().parse::<i32>()?;   // ? propagates Err
    Ok(n)                                // wrap success in Ok
}

// Handle at call site
match parse("42") {
    Ok(n)  => println!("got {}", n),
    Err(e) => println!("failed: {}", e),
}

// unwrap/expect — only in prototypes
let n = parse("42").unwrap();        // panics if Err
let n = parse("42").expect("msg");   // panics with message

