use std::num::ParseIntError;

fn parse_age(s: &str) -> Result<u32, ParseIntError> {
    let n: u32 = s.trim().parse()?;
    Ok(n)
}

fn main() {
    match parse_age("25") {
        Ok(age) => println!("age = {}", age),
        Err(e)  => println!("error: {}", e),
    }
    match parse_age("abc") {
        Ok(age) => println!("age = {}", age),
        Err(e)  => println!("error: {}", e),
    }
}

