practice.solutionCode:
fn safe_divide(a: f64, b: f64) -> Result<f64, String> {
    if b == 0.0 {
        Err(String::from("division by zero"))
    } else {
        Ok(a / b)
    }
}

fn main() {
    match safe_divide(10.0, 2.0) {
        Ok(v)  => println!("{}", v),
        Err(e) => println!("Error: {}", e),
    }
}
